0	//! Merge data from a source dataset with the target Delta Table based on a join
1	//! predicate.  A full outer join is performed which results in source and
2	//! target records that match, source records that do not match, or target
3	//! records that do not match.
4	//!
5	//! Users can specify update, delete, and insert operations for these categories
6	//! and specify additional predicates for finer control. The order of operations
7	//! specified matter.  See [`MergeBuilder`] for more information
8	//!
9	//! # Example
10	//! ```rust ignore
11	//! let table = open_table(Url::from_directory_path("/abs/path/to/table").unwrap())?;
12	//! let (table, metrics) = DeltaOps(table)
13	//!     .merge(source, col("target.id").eq(col("source.id")))
14	//!     .with_source_alias("source")
15	//!     .with_target_alias("target")
16	//!     .when_matched_update(|update| {
17	//!         update
18	//!             .update("value", col("source.value") + lit(1))
19	//!             .update("modified", col("source.modified"))
20	//!     })?
