0	//! Kernel-based Delta table scanning with optimized query execution.
1	//!
2	//! This module provides efficient table scanning using Delta Kernel, integrating with
3	//! DataFusion's query engine. It supports:
4	//!
5	//! - **Physical scan execution** ([`DeltaScanExec`]) - Reads Parquet data files and applies
6	//!   Delta protocol transformations (column mapping, deletion vectors, partition values)
7	//! - **Metadata-only scans** ([`DeltaScanMetaExec`]) - Answers queries like `COUNT(*)`
8	//!   using file statistics without reading data files
9	//! - **Predicate pushdown** - Pushes filters to both kernel file skipping and Parquet readers
10	//!   for efficient data pruning
11	//! - **Multi-store support** - Handles files across different object stores in a single query
12	//!
13	//! The scan planning process in [`plan`] determines which files to read and how to apply
14	//! predicates, while execution plans handle the actual data reading and transformation.
15	
16	use std::{collections::VecDeque, pin::Pin, sync::Arc};
17	
18	use arrow_array::{ArrayRef, RecordBatch};
19	use arrow_cast::{CastOptions, cast_with_options};
20	use arrow_schema::{FieldRef, Schema, SchemaBuilder, SchemaRef};
21	use chrono::{TimeZone as _, Utc};
22	use dashmap::DashMap;
23	use datafusion::{
24	    catalog::Session,
25	    common::{
26	        ColumnStatistics, HashMap, Result, Statistics, ToDFSchema, plan_err, stats::Precision,
27	    },
28	    config::TableParquetOptions,
29	    datasource::physical_plan::{ParquetSource, parquet::CachedParquetFileReaderFactory},
30	    error::DataFusionError,
31	    execution::object_store::ObjectStoreUrl,
32	    physical_plan::{
33	        ExecutionPlan,
34	        empty::EmptyExec,
35	        metrics::{ExecutionPlanMetricsSet, MetricBuilder},
36	        union::UnionExec,
37	    },
38	    prelude::Expr,
39	};
40	use datafusion_datasource::{
41	    PartitionedFile, TableSchema, compute_all_files_statistics, file_groups::FileGroup,
42	    file_scan_config::FileScanConfigBuilder, source::DataSourceExec,
43	};
44	use datafusion_physical_expr_adapter::{BatchAdapter, BatchAdapterFactory};
45	use delta_kernel::{
46	    Engine, Expression, expressions::StructData, scan::ScanMetadata, table_features::TableFeature,
47	};
48	use futures::{Stream, TryStreamExt as _, future::ready};
49	use itertools::Itertools as _;
50	use object_store::{ObjectMeta, path::Path};
51	use url::Url;
52	
53	pub use self::exec::DeltaScanExec;
54	use self::exec_meta::DeltaScanMetaExec;
55	pub(crate) use self::plan::{KernelScanPlan, supports_filters_pushdown};
56	use self::replay::{ScanFileContext, ScanFileStream};
57	use super::FileSelection;
58	use crate::{
59	    DeltaTableError,
60	    delta_datafusion::{
61	        DeltaScanConfig,
62	        engine::{AsObjectStoreUrl as _, to_datafusion_scalar},
63	        file_id::wrap_file_id_value,
64	        table_provider::next::DeletionVectorSelection,
65	    },
66	};
67	
68	mod exec;
69	mod exec_meta;
70	mod plan;
71	mod replay;
72	
73	type ScanMetadataStream = Pin<Box<dyn Stream<Item = Result<ScanMetadata, DeltaTableError>> + Send>>;
74	
75	pub(super) async fn execution_plan(
76	    config: &DeltaScanConfig,
77	    session: &dyn Session,
78	    scan_plan: KernelScanPlan,
79	    stream: ScanMetadataStream,
80	    engine: Arc<dyn Engine>,
81	    limit: Option<usize>,
82	    file_selection: Option<&FileSelection>,
83	) -> Result<Arc<dyn ExecutionPlan>> {
84	    let (files, transforms, dvs, metrics) =
85	        replay_files(engine, &scan_plan, config.clone(), stream, file_selection).await?;
86	
87	    let file_id_field = config.file_id_field();
88	    if scan_plan.is_metadata_only() {
89	        let map_file = |f: &ScanFileContext| {
90	            Ok((
91	                f.file_url.to_string(),
92	                match &f.stats.num_rows {
93	                    Precision::Exact(n) => *n,
94	                    _ => {
95	                        return plan_err!(
96	                            "Expected exact row counts in file: {}",
97	                            super::redact_url_for_error(&f.file_url)
98	                        );
99	                    }
100	                },
101	            ))
102	        };
103	
104	        let maybe_file_rows = files
105	            .iter()
106	            .map(map_file)
107	            .try_collect::<_, VecDeque<_>, _>();
108	        if let Ok(file_rows) = maybe_file_rows {
109	            let exec = DeltaScanMetaExec::new(
110	                Arc::new(scan_plan),
111	                vec![file_rows],
112	                Arc::new(transforms),
113	                Arc::new(dvs),
114	                config.retain_file_id().then_some(file_id_field),
115	                metrics,
116	            );
117	            return Ok(Arc::new(exec) as _);
118	        }
119	    }
120	
121	    get_data_scan_plan(
122	        session,
123	        scan_plan,
124	        files,
125	        transforms,
126	        dvs,
127	        metrics,
128	        limit,
129	        file_id_field,
130	        config.retain_file_id(),
131	    )
132	    .await
133	}
134	
135	/// Materialize deletion vector keep masks for every file in the scan that has one.
136	///
137	/// Deletion vectors are loaded as a side-effect of consuming [`ScanFileStream`].  We drain the
138	/// full stream here (discarding file contexts, stats, and partition values) because the DV
139	/// loading tasks are spawned lazily during stream poll.  A dedicated DV-only stream that skips
140	/// stats parsing is possible but not yet warranted — this path is not latency-sensitive and the
141	/// file-list is typically small.
142	///
143	/// [`ReceiverStreamBuilder::build`] returns a merged stream that includes a JoinSet checker;
144	/// `.try_collect().await` below will not complete until every spawned DV-loading task has
145	/// finished, so no results are lost.
146	pub(super) async fn replay_deletion_vectors(
147	    engine: Arc<dyn Engine>,
148	    scan_plan: &KernelScanPlan,
149	    config: &DeltaScanConfig,
150	    stream: ScanMetadataStream,
151	) -> Result<Vec<DeletionVectorSelection>> {
152	    let mut stream = ScanFileStream::new(engine, &scan_plan.scan, config.clone(), None, stream);
153	    while stream.try_next().await?.is_some() {}
154	
155	    let dv_stream = stream.dv_stream.build();
156	    // Only files with `dv_info.has_vector()` spawn tasks, so every item should carry a DV.
157	    // Guard with a typed error (instead of panic) in case that invariant drifts.
158	    let dvs: DashMap<_, _> = dv_stream
159	        .and_then(|(url, dv, num_records)| {
160	            ready(match dv {
161	                Some(keep_mask) => normalize_dv_keep_mask_for_api(keep_mask, num_records, &url)
162	                    .map(|mask| (url.to_string(), mask))
163	                    .map_err(DeltaTableError::from),
164	                None => Err(DeltaTableError::generic(
165	                    "Invariant violation: DV task spawned for file without deletion vector",
166	                )),
167	            })
168	        })
169	        .try_collect()
170	        .await?;
171	
172	    let mut vectors: Vec<_> = dvs
173	        .into_iter()
174	        .map(|(filepath, keep_mask)| DeletionVectorSelection {
175	            filepath,
176	            keep_mask,
177	        })
178	        .collect();
179	    vectors.sort_unstable_by(|left, right| left.filepath.cmp(&right.filepath));
180	    Ok(vectors)
181	}
182	
183	async fn replay_files(
184	    engine: Arc<dyn Engine>,
185	    scan_plan: &KernelScanPlan,
186	    scan_config: DeltaScanConfig,
187	    stream: ScanMetadataStream,
188	    file_selection: Option<&FileSelection>,
189	) -> Result<(
190	    Vec<ScanFileContext>,
191	    HashMap<String, Arc<Expression>>,
192	    DashMap<String, Vec<bool>>,
193	    ExecutionPlanMetricsSet,
194	)> {
195	    let mut stream = ScanFileStream::new(
196	        engine,
197	        &scan_plan.scan,
198	        scan_config,
199	        file_selection.map(|selection| &selection.file_ids),
200	        stream,
201	    );
202	    let mut files = Vec::new();
203	    while let Some(file) = stream.try_next().await? {
204	        files.extend(file);
205	    }
206	
207	    if let Some(selection) = file_selection
208	        && selection.missing_file_policy == super::MissingFilePolicy::Error
209	    {
210	        let found: std::collections::HashSet<_> =
211	            files.iter().map(|f| f.file_url.to_string()).collect();
212	        let all_missing: Vec<_> = selection.file_ids.difference(&found).sorted().collect();
213	
214	        if !all_missing.is_empty() {
215	            let missing_total = all_missing.len();
216	            let missing: Vec<_> = all_missing
217	                .iter()
218	                .take(10)
219	                .map(|id| super::redact_url_str_for_error(id))
220	                .collect();
221	            let extra = if missing_total > missing.len() {
222	                format!(" (and {} more)", missing_total - missing.len())
223	            } else {
224	                String::new()
225	            };
226	            return plan_err!(
227	                "File selection contains {missing_total} missing files (showing up to 10, redacted): {}{extra}",
228	                missing.join(", ")
229	            );
230	        }
231	    }
232	
233	    let transforms: HashMap<_, _> = files
234	        .iter_mut()
235	        .flat_map(|file| {
236	            file.transform
237	                .take()
238	                .map(|t| (file.file_url.to_string(), t))
239	        })
240	        .collect();
241	
242	    let dv_stream = stream.dv_stream.build();
243	    let dvs: DashMap<_, _> = dv_stream
244	        .try_filter_map(|(url, dv, _)| ready(Ok(dv.map(|dv| (url.to_string(), dv)))))
245	        .try_collect()
246	        .await?;
247	
248	    let metrics = ExecutionPlanMetricsSet::new();
249	    MetricBuilder::new(&metrics)
250	        .global_counter("count_files_scanned")
251	        .add(stream.metrics.num_scanned);
252	
253	    Ok((files, transforms, dvs, metrics))
254	}
255	
256	/// Normalize a DV keep mask for `deletion_vectors()`.
257	///
258	/// Kernel returns a sparse mask (up to the highest deleted row index). For API output we need one
259	/// full mask per file, to do this we pad trailing entries with `true` up to `numRecords`. If `numRecords`
260	/// is missing we fail, because we cannot know the correct full length.
261	///
262	/// This is API only. Scan execution does per batch normalization in `exec::consume_dv_mask` and
263	/// `exec_meta::apply_selection_vector`.
264	fn normalize_dv_keep_mask_for_api(
265	    mut mask: Vec<bool>,
266	    num_records: Option<u64>,
267	    file_url: &Url,
268	) -> Result<Vec<bool>> {
269	    let redacted_url = super::redact_url_for_error(file_url);
270	    let Some(num_records) = num_records else {
271	        return plan_err!(
272	            "Missing numRecords for file with deletion vector: {}",
273	            redacted_url
274	        );
275	    };
276	    let num_records = usize::try_from(num_records).map_err(|_| {
277	        DataFusionError::Execution(format!(
278	            "numRecords does not fit usize for file with deletion vector: {redacted_url}"
279	        ))
280	    })?;
281	    if mask.len() > num_records {
282	        return plan_err!(
283	            "Deletion vector mask length {} exceeds numRecords {} for file: {}",
284	            mask.len(),
285	            num_records,
286	            redacted_url
287	        );
288	    }
289	    mask.resize(num_records, true);
290	    Ok(mask)
291	}
292	
293	async fn get_data_scan_plan(
294	    session: &dyn Session,
295	    scan_plan: KernelScanPlan,
296	    files: Vec<ScanFileContext>,
297	    transforms: HashMap<String, Arc<Expression>>,
298	    dvs: DashMap<String, Vec<bool>>,
299	    metrics: ExecutionPlanMetricsSet,
300	    limit: Option<usize>,
301	    file_id_field: FieldRef,
302	    retain_file_ids: bool,
303	) -> Result<Arc<dyn ExecutionPlan>> {
304	    let mut partition_stats = HashMap::new();
305	
306	    // Convert the files into datafusions `PartitionedFile`s grouped by the object store they are stored in
307	    // this is used to create a DataSourceExec plan for each store
308	    // To correlate the data with the original file, we add the file url as a partition value
309	    // This is required to apply the correct transform to the data in downstream processing.
310	    let to_partitioned_file = |f: ScanFileContext| {
311	        if let Some(part_stata) = &f.partitions {
312	            update_partition_stats(part_stata, &f.stats, &mut partition_stats)?;
313	        }
