45	/// Consume the per-file deletion-vector keep-mask for the current batch.
46	///
47	/// The keep-mask is stored once per file and consumed incrementally as parquet
48	/// batches are produced:
49	/// - If the mask is shorter than the batch, missing trailing entries are
50	///   treated as `true` (keep row).
51	/// - If the mask is longer than the batch, the remainder is preserved for the
52	///   next batch from the same file.
53	///
54	/// This function intentionally does not error when `selection_vector.len()` is
55	/// greater than `batch_num_rows`; that is expected when one file spans multiple
56	/// input batches.
57	pub(crate) fn consume_dv_mask(
58	    selection_vector: &mut Vec<bool>,
59	    batch_num_rows: usize,
60	) -> DvMaskResult {
61	    if selection_vector.is_empty() {
62	        return DvMaskResult {
63	            selection: None,
64	            should_remove: true,
65	        };
66	    }
67	
68	    if selection_vector.len() >= batch_num_rows {
69	        let sv: Vec<bool> = selection_vector.drain(0..batch_num_rows).collect();
70	        let is_empty = selection_vector.is_empty();
71	        DvMaskResult {
72	            selection: Some(sv),
73	            should_remove: is_empty,
74	        }
75	    } else {
76	        let mut sv: Vec<bool> = std::mem::take(selection_vector);
77	        sv.resize(batch_num_rows, true);
78	        DvMaskResult {
79	            selection: Some(sv),
80	            should_remove: true,
81	        }
82	    }
83	}
