            evaluator
                .evaluate_arrow(batch)
                .map_err(|e| DataFusionError::External(Box::new(e)))?
        } else {
            batch
        };

        if self.return_file_ids {
            super::finalize_transformed_batch(
                result,
                &self.scan_plan,
                Some((file_id_col, Arc::new(file_id_field))),
                &mut self.schema_adapter,
            )
        } else {
            super::finalize_transformed_batch(
                result,
                &self.scan_plan,
                None,
                &mut self.schema_adapter,
            )
        }
    }
}

